import{_ as s,o as i,c as a,ak as t}from"./chunks/framework.BwzOvEE0.js";const k=JSON.parse('{"title":"Security","description":"How mcp-exec sandboxes code execution — OS-level isolation, env filtering, network policy, and hook opacity.","frontmatter":{"description":"How mcp-exec sandboxes code execution — OS-level isolation, env filtering, network policy, and hook opacity."},"headers":[],"relativePath":"guide/security.md","filePath":"guide/security.md","lastUpdated":1779829281000}'),o={name:"guide/security.md"};function n(l,e,d,c,r,h){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>mcp-exec enforces isolation at the OS level via <code>@anthropic-ai/sandbox-runtime</code>. Restrictions apply to all child processes — there is no language-level bypass.</p><h2 id="sandbox-isolation" tabindex="-1">Sandbox isolation <a class="header-anchor" href="#sandbox-isolation" aria-label="Permalink to &quot;Sandbox isolation&quot;">​</a></h2><p>Every <code>exec()</code> call runs inside a restricted OS-level sandbox:</p><ul><li><strong>Network:</strong> outbound requests are blocked by default; <code>allowedDomains</code> in <code>sandbox.network</code> controls what hostnames are reachable</li><li><strong>Filesystem:</strong> writes are blocked except <code>/tmp</code> by default; <code>allowWrite</code> and <code>denyRead</code>/<code>denyWrite</code> control access</li><li><strong>Process:</strong> child processes inherit the same sandbox restrictions; they cannot escalate privileges</li></ul><p>The sandbox policy is global and set in <code>~/.claude/settings.json</code> or <code>.claude/settings.json</code>. It cannot be overridden per-call (only <code>env</code> and <code>timeout</code> are per-call configurable).</p><p>See <a href="/mcp-exec/guide/configuration.html">Configuration →</a> for the full <code>sandbox</code> block reference.</p><h2 id="environment-variable-filtering" tabindex="-1">Environment variable filtering <a class="header-anchor" href="#environment-variable-filtering" aria-label="Permalink to &quot;Environment variable filtering&quot;">​</a></h2><p>By default, only a safe minimal set of env vars is forwarded from your shell into Bash and Python subprocesses. This prevents credentials, API keys, and tokens from leaking into sandboxed code unintentionally.</p><p><strong>Default allowlist:</strong> <code>PATH</code>, <code>HOME</code>, <code>TMPDIR</code>, <code>TMP</code>, <code>TEMP</code>, <code>USER</code>, <code>USERNAME</code>, <code>LANG</code>, <code>LC_ALL</code>, <code>LC_CTYPE</code>, <code>NODE_PATH</code>, <code>SHELL</code></p><p>Everything else — <code>GITHUB_TOKEN</code>, <code>AWS_SECRET_ACCESS_KEY</code>, custom API keys — is stripped before the child process spawns.</p><p>To forward additional vars:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mcp-exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GITHUB_TOKEN</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # user-level</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mcp-exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GITHUB_TOKEN</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --local</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # project-level</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mcp-exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       # see what passes vs blocks</span></span></code></pre></div><p>The Node runtime uses <code>vm.Context</code> and does not spawn a subprocess, so its env exposure is limited to the parent process scope.</p><p>See <a href="/mcp-exec/guide/cli.html#mcp-exec-env">CLI Reference → mcp-exec env</a> for full subcommand documentation.</p><h2 id="hook-opacity" tabindex="-1">Hook opacity <a class="header-anchor" href="#hook-opacity" aria-label="Permalink to &quot;Hook opacity&quot;">​</a></h2><p><code>PreToolUse</code>/<code>PostToolUse</code> hooks watching downstream MCP tool names will <strong>not</strong> fire when those tools are called inside <code>exec()</code>. The sandbox is opaque to the Claude Code event system.</p><p>If you need to observe which tools were called inside a sandbox run, use the <code>tool_calls</code> field on the exec result:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">result</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">tool_calls</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> exec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ runtime: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;node&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, code: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`...\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// tool_calls: [{ server: &quot;github&quot;, name: &quot;listPullRequests&quot;, args: {...}, result: {...} }]</span></span></code></pre></div><h2 id="credential-handling" tabindex="-1">Credential handling <a class="header-anchor" href="#credential-handling" aria-label="Permalink to &quot;Credential handling&quot;">​</a></h2><p>mcp-exec does not have a credential system. Authentication tokens reach MCP servers via env vars present in the shell environment (<code>.env</code>, direnv, secrets manager, etc.) — the same mechanism the MCP servers themselves use. No credentials are stored, proxied, or managed by mcp-exec.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/mcp-exec/guide/configuration.html">Configuration →</a> — sandbox policy reference</li><li><a href="/mcp-exec/guide/cli.html">CLI Reference →</a> — env allowlist management</li></ul>`,23)])])}const u=s(o,[["render",n]]);export{k as __pageData,u as default};
